let otpInputs2 = $(".mob_otp_input2"),
  otpBox01 = $("#otp01"),
  otpBox02 = $("#otp02"),
  otpBox03 = $("#otp03"),
  otpBox04 = $("#otp04"),
  errorMsgLogin = $("#errorMsgLogin"),
  errorMsgLogin2 = $("#errorMsgLogin2"),
  academyClick = $(".new_login_menu"),
  menuBox = $(".new_menu_box"),
  manage = $(".mob_academy_manage"),
  register = $("#city_register"),
  phoneNumberSpan2 = $("#phoneNumberSpan2"),
  termsCheckboxLogin = $('#login_check input[type="checkbox"]');
function sendOtpForLogin(o, e) {
  $.ajax({
    type: "POST",
    url: "/otp/send",
    data: {
      _token: $('meta[name="csrf-token"]').attr("content"),
      phone: o,
      type: e,
    },
    dataType: "json",
    success: (o) => {
      0 == o.status && "login_otp" == e
        ? (errorMsgLogin.text(o.message), errorMsgLogin.removeClass("d-none"))
        : 1 == o.status && "resend_login_otp" == e
        ? (errorMsgLogin.addClass("d-none"),
          $("#btn-signup2").prop("disabled", !0),
          $("#btn-signup2").addClass("disable_btn"),
          $("#btn-signup2").removeClass("mob_login_create_profile_btn"),
          $("#resend-otp_login").hide(),
          $("#time2").show(),
          countdown2())
        : ($("#btn-signup2").prop("disabled", !0),
          $("#btn-signup2").addClass("disable_btn"),
          $("#btn-signup2").removeClass("mob_login_create_profile_btn"),
          errorMsgLogin2.addClass("d-none"),
          loginContent.css("display", "none"),
          authenticationScreen2.css("display", "block"),
          otpBox01.focus(),
          countdown2());
    },
    error: (o) => {
      errorMsgLogin2.text(o), errorMsgLogin2.removeClass("d-none");
    },
  });
}
function countdown2() {
  let o = 120,
    e = setInterval(function () {
      let n = Math.floor(o / 60),
        t = o % 60;
      if (o <= 0)
        return (
          clearInterval(e),
          $("#resend-otp_login").show(),
          void $("#time2").hide()
        );
      $("#time2").text("RESENT OTP IN " + n + "m " + t + "s"), o--;
    }, 1e3);
}
otpInputs2.on("input", function (o) {
  let e = otpInputs2.index(this);
  1 === o.target.value.length
    ? e < otpInputs2.length - 1 && otpInputs2.eq(e + 1).focus()
    : 0 === o.target.value.length && e > 0 && otpInputs2.eq(e - 1).focus();
}),
  otpInputs2.on("keydown", function (o) {
    let e = otpInputs2.index(this);
    "Backspace" === o.key &&
      0 === o.target.value.length &&
      e > 0 &&
      otpInputs2.eq(e - 1).focus();
  }),
  otpInputs2.on("keypress", function (o) {
    $(this).val().length >= 1 && o.preventDefault();
  }),
  $("#otp01, #otp02, #otp03, #otp04").on("input", function () {
    var o = !0;
    $("#otp01, #otp02, #otp03, #otp04").each(function () {
      if ("" === $(this).val()) return (o = !1), !1;
    }),
      o
        ? ($("#btn-signup2").prop("disabled", !1),
          $("#btn-signup2").removeClass("disable_btn"),
          $("#btn-signup2").addClass("mob_login_create_profile_btn"))
        : ($("#btn-signup2").prop("disabled", !0),
          $("#btn-signup2").addClass("disable_btn"),
          $("#btn-signup2").removeClass("mob_login_create_profile_btn"));
  }),
  $("#resend-otp_login").click(() => {
    sendOtpForLogin(numberValidation.val(), "resend_login_otp");
  }),
  $("#loginOtpBtn").on("click", function () {
    0 === numberValidation.val().length
      ? (errorMsgLogin.text("Please Enter Mobile Number"),
        errorMsgLogin.removeClass("d-none"))
      : 10 !== numberValidation.val().length
      ? (errorMsgLogin.text("Please Enter only 10 digits"),
        errorMsgLogin.removeClass("d-none"))
      : termsCheckboxLogin.prop("checked")
      ? ($.ajax({
          type: "POST",
          url: "/api/check-user-exist",
          data: { phone: numberValidation.val(), _token: $('meta[name="csrf-token"]').attr("content") },
          dataType: "json",
          success: (o) => {
            0 == o.status
              ? (errorMsgLogin.text("User Not Exists."),
                errorMsgLogin.removeClass("d-none"))
              : sendOtpForLogin(numberValidation.val(), "login_otp");
          },
          error: (o) => {
            errorMsgLogin.text(o), errorMsgLogin.removeClass("d-none");
          },
        }),
        phoneNumberSpan2 &&
          phoneNumberSpan2.text("+91" + numberValidation.val()))
      : (errorMsgLogin.text("Please accept the Terms and Privacy Policy"),
        errorMsgLogin.removeClass("d-none"));
  }),
  otpBox04.on("input", function () {
    if (otpBox01.val() && otpBox02.val() && otpBox03.val() && otpBox04.val()) {
      let o = numberValidation.val(),
        e = (
          otpBox01.val() +
          otpBox02.val() +
          otpBox03.val() +
          otpBox04.val()
        ).toString();
      if (e.length <= 3)
        return (
          errorMsgLogin2.text("Invalid OTP"),
          void errorMsgLogin2.removeClass("d-none")
        );
      $.ajax({
        type: "POST",
        url: "/login/validate",
        data: {
          _token: $('meta[name="csrf-token"]').attr("content"),
          mobile: o,
          otp: e,
        },
        dataType: "json",
        success: (o) => {
          1 == o.status
            ? null != o.redirect_url
              ? (window.location.href = o.redirect_url)
              : location.reload()
            : (errorMsgLogin2.text(o.message),
              errorMsgLogin2.removeClass("d-none"));
        },
        error: (o) => {
          errorMsgLogin2.text(JSON.stringify(o)),
            errorMsgLogin2.removeClass("d-none");
        },
      });
    }
  }),
  academyClick &&
    menuBox &&
    (academyClick.on("click", (o) => {
      o.stopPropagation(), menuBox.css("display", "flex");
    }),
    $(document).on("click", () => {
      menuBox.css("display", "none");
    }),
    menuBox.on("click", (o) => {
      o.stopPropagation();
    })),
  menuBox &&
    $(".help_top").click(function () {
      $(".new_menu_box").hide(), $("#helpPopup").show();
    }),
  register &&
    $("#city_register").click(function () {
      $("#signupPopup").show();
    }),
  manage &&
    $(".mob_academy_manage").click(function () {
      $("#loginPopup").show();
    }),
  $("#openLoginPopup2").on("click", function () {
    $(".profile_modal").hide(),
      $(".profile_wrapper").hide(),
      $("#loginPopup").show();
  }),
  $("#openLoginPopup2").on("click", function () {
    $(".profile_modal").hide(),
      $(".profile_wrapper").hide(),
      $(".login_content").show(),
      $(".authentication_screen2").hide(),
      $("#username").val(""),
      $("#otp01").val(""),
      $("#otp02").val(""),
      $("#otp03").val(""),
      $("#otp04").val(""),
      $("#loginPopup").show();
  }),
  $("#search_icon").on("click", function () {
    $("#mob_search_display").toggle();
  }),
  $(document).ready(function () {
    $(".profile_wrapper").click(function (o) {
      o.target === this &&
        ($(".profile_modal").hide(),
        $(this).hide(),
        $("#helpButton").show(),
        $(".scroll_icon").show());
    }),
      $(".profile_modal").click(function (o) {
        o.stopPropagation();
      });

      $('#loginWithOtpBtn').click(function() {
        $('.login_with_otp').show();
        $('.login_with_pin').hide();
    });

    $('#loginWithPinBtn').click(function() {
        $('.login_with_otp').hide();
        $('.login_with_pin').show();
    });
  });
